# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify, url_for
import sqlite3
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

# Database setup (SQLite for simplicity)
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users (email TEXT, reset_token TEXT)''')
    conn.commit()
    conn.close()

@app.route('/reset-password', methods=['POST'])
def reset_password():
    data = request.json
    email = data.get('email')

    # Generate a random token
    token = secrets.token_urlsafe(16)

    # Store the token in the database with the user's email
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("INSERT INTO users (email, reset_token) VALUES (?, ?)", (email, token))
    conn.commit()
    conn.close()

    # Send the reset link
    send_reset_email(email, token)

    return jsonify({"message": "Reset email sent"}), 200

def send_reset_email(email, token):
    msg = MIMEText(f"Click here to reset your password: {url_for('reset', token=token, _external=True)}")
    msg['Subject'] = 'Password Reset'
    msg['From'] = 'no-reply@example.com'
    msg['To'] = email

    # Simple SMTP setup (use a real SMTP server for production)
    with smtplib.SMTP('localhost') as s:
        s.send_message(msg)

@app.route('/reset/<token>', methods=['GET'])
def reset(token):
    # For simplicity, just return the token in the response
    return jsonify({"token": token}), 200

if __name__ == '__main__':
    init_db()
    app.run(debug=True)